t\t}\n\t}\n\traft.SetLogger(lg)\n\tr := &raftNode{\n\t\tlg:             cfg.lg,\n\t\ttickMu:         new(sync.RWMutex),\n\t\traftNodeConfig: cfg,\n\t\tlatestTickTs:   time.Now(),\n\t\t// set up contention detectors for raft heartbeat message.\n\t\t// expect to send a heartbeat within 2 heartbeat intervals.\n\t\ttd:         contention.NewTimeoutDetector(2 * cfg.heartbeat),\n\t\treadStateC: make(chan raft.ReadState, 1),\n\t\tmsgSnapC:   make(chan raftpb.Message, maxInFlightMsgSnap),\n\t\tapplyc:     make(chan toApply),\n\t\tstopped:    make(chan struct{}),\n\t\tdone:       make(chan struct{}),\n\t}\n\tif r.heartbeat == 0 {\n\t\tr.ticker = &time.Ticker{}\n\t} else {\n\t\tr.ticker = time.NewTicker(r.heartbeat)\n\t}\n\treturn r\n}\n\n// raft.Node does not have locks in Raft package\nfunc (r *raftNode) tick() {\n\tr.tickMu.Lock()\n\tr.Tick()\n\tr.latestTickTs = time.Now()\n\tr.tickMu.Unlock()\n}\n\nfunc (r *raftNode) getLatestTickTs() time.Time {\n\tr.tickMu.RLock()\n\tdefer r.tickMu.RUnlock()\n\treturn r.latestTickTs\n}\n\n// start prepares and starts raftNode in a new goroutine. It is no longer safe\n// to modify the fields after it has been started.\nfunc (r *raftNode) start(rh *raftReadyHandler) {\n\tinternalTimeout := time.Second\n\n\tgo func() {\n\t\tdefer r.onStop()\n\t\tislead := false\n\n\t\tfor {\n\t\t\tselect {\n\t\t\tcase <-r.ticker.C:\n\t\t\t\tr.tick()\n\t\t\tcase rd := <-r.Ready():\n\t\t\t\tif rd.SoftState != nil {\n\t\t\t\t\tnewLeader := rd.SoftState.Lead != raft.None && rh.getLead() != rd.SoftState.Lead\n\t\t\t\t\tif newLeader {\n\t\t\t\t\t\tleaderChanges.Inc()\n\t\t\t\t\t}\n\n\t\t\t\t\tif rd.SoftState.Lead == raft.None {\n\t\t\t\t\t\thasLeader.Set(0)\n\t\t\t\t\t} else {\n\t\t\t\t\t\thasLeader.Set(1)\n\t\t\t\t\t}\n\n\t\t\t\t\trh.updateLead(rd.SoftState.Lead)\n\t\t\t\t\tislead = rd.RaftState == raft.StateLeader\n\t\t\t\t\tif islead {\n\t\t\t\t\t\tisLeader.Set(1)\n\t\t\t\t\t} else {\n\t\t\t\t\t\tisLeader.Set(0)\n\t\t\t\t\t}\n\t\t\t\t\trh.updateLeadership(newLeader)\n\t\t\t\t\tr.td.Reset()\n\t\t\t\t}\n\n\t\t\t\tif len(rd.ReadStates) != 0 {\n\t\t\t\t\tselect {\n\t\t\t\t\tcase r.readStateC <- rd.ReadStates[len(rd.ReadStates)-1]:\n\t\t\t\t\tcase <-time.After(internalTimeout):\n\t\t\t\t\t\tr.lg.Warn(\"timed out sending read state\", zap.Duration(\"timeout\", internalTimeout))\n\t\t\t\t\tcase <-r.stopped:\n\t\t\t\t\t\treturn\n\t\t\t\t\t}\n\t\t\t\t}\n\n\t\t\t\tnotifyc := make(chan struct{}, 1)\n\t\t\t\traftAdvancedC := make(chan struct{}, 1)\n\t\t\t\tap := toApply{\n\t\t\t\t\tentries:       rd.CommittedEntries,\n\t\t\t\t\tsnapshot:      rd.Snapshot,\n\t\t\t\t\tnotifyc:       notifyc,\n\t\t\t\t\traftAdvancedC: raftAdvancedC,\n\t\t\t\t}\n\n\t\t\t\tupdateCommittedIndex(&ap, rh)\n\n\t\t\t\tselect {\n\t\t\t\tcase r.applyc <- ap:\n\t\t\t\tcase <-r.stopped:\n\t\t\t\t\treturn\n\t\t\t\t}\n\n\t\t\t\t// the leader can write to its disk in parallel with replicating to the followers and then\n\t\t\t\t// writing to their disks.\n\t\t\t\t// For more details, check raft thesis 10.2.1\n\t\t\t\tif islead {\n\t\t\t\t\t// gofail: var raftBeforeLeaderSend struct{}\n\t\t\t\t\tr.transport.Send(r.processMessages(rd.Messages))\n\t\t\t\t}\n\n\t\t\t\t// Must save the snapshot file and WAL snapshot entry before saving any other entries or hardstate to\n\t\t\t\t// ensure that recovery after a snapshot restore is possible.\n\t\t\t\tif !raft.IsEmptySnap(rd.Snapshot) {\n\t\t\t\t\t// gofail: var raftBeforeSaveSnap struct{}\n\t\t\t\t\tif err := r.storage.SaveSnap(rd.Snapshot); err != nil {\n\t\t\t\t\t\tr.lg.Fatal(\"failed to save Raft snapshot\", zap.Error(err))\n\t\t\t\t\t}\n\t\t\t\t\t// gofail: var raftAfterSaveSnap struct{}\n\t\t\t\t}\n\n\t\t\t\t// gofail: var raftBeforeSave struct{}\n\t\t\t\tif err := r.storage.Save(rd.HardState, rd.Entries); err != nil {\n\t\t\t\t\tr.lg.Fatal(\"failed to save Raft hard state and entries\", zap.Error(err))\n\t\t\t\t}\n\t\t\t\tif !raft.IsEmptyHardState(rd.HardState) {\n\t\t\t\t\tproposalsCommitted.Set(float64(rd.HardState.Commit))\n\t\t\t\t}\n\t\t\t\t// gofail: var raftAfterSave struct{}\n\n\t\t\t\tif !raft.IsEmptySnap(rd.Snapshot) {\n\t\t\t\t\t// Force WAL to fsync its hard state before Release() releases\n\t\t\t\t\t// old data from the WAL. Otherwise could get an error like:\n\t\t\t\t\t// panic: tocommit(107) is out of range [lastIndex(84)]. Was the raft log corrupted, truncated, or lost?\n\t\t\t\t\t// See https://github.com/etcd-io/etcd/issues/10219 for more details.\n\t\t\t\t\tif err := r.storage.Sync(); err != nil {\n\t\t\t\t\t\tr.lg.Fatal(\"failed to sync Raft snapshot\", zap.Error(err))\n\t\t\t\t\t}\n\n\t\t\t\t\t// etcdserver now claim the snapshot has been persisted onto the disk\n\t\t\t\t\tnotifyc <- struct{}{}\n\n\t\t\t\t\t// gofail: var raftBeforeApplySnap struct{}\n\t\t\t\t\tr.raftStorage.ApplySnapshot(rd.Snapshot)\n\t\t\t\t\tr.lg.Info(\"applied incoming Raft snapshot\", zap.Uint64(\"snapshot-index\", rd.Snapshot.Metadata.Index))\n\t\t\t\t\t// gofail: var raftAfterApplySnap struct{}\n\n\t\t\t\t\tif err := r.storage.Release(rd.Snapshot); err != nil {\n\t\t\t\t\t\tr.lg.Fatal(\"failed to release Raft wal\", zap.Error(err))\n\t\t\t\t\t}\n\t\t\t\t\t// gofail: var raftAfterWALRelease struct{}\n\t\t\t\t}\n\n\t\t\t\tr.raftStorage.Append(rd.Entries)\n\n\t\t\t\tconfChanged := false\n\t\t\t\tfor _, ent := range rd.CommittedEntries {\n\t\t\t\t\tif ent.Type == raftpb.EntryConfChange {\n\t\t\t\t\t\tconfChanged = true\n\t\t\t\t\t\tbreak\n\t\t\t\t\t}\n\t\t\t\t}\n\n\t\t\t\tif !islead {\n\t\t\t\t\t// finish processing incoming messages before we signal notifyc chan\n\t\t\t\t\tmsgs := r.processMessages(rd.Messages)\n\n\t\t\t\t\t// now unblocks 'applyAll' that waits on Raft log disk writes before triggering snapshots\n\t\t\t\t\tnotifyc <- struct{}{}\n\n\t\t\t\t\t// Candidate or follower needs to wait for all pending configuration\n\t\t\t\t\t// changes to be applied before sending messages.\n\t\t\t\t\t// Otherwise we might incorrectly count votes (e.g. votes from removed members).\n\t\t\t\t\t// Also slow machine's follower raft-layer could proceed to become the leader\n\t\t\t\t\t// on its own single-node cluster, before toApply-layer applies the config change.\n\t\t\t\t\t// We simply wait for ALL pending entries to be applied for now.\n\t\t\t\t\t// We might improve this later on if it causes unnecessary long blocking issues.\n\n\t\t\t\t\tif confChanged {\n\t\t\t\t\t\t// blocks until 'applyAll' calls 'applyWait.Trigger'\n\t\t\t\t\t\t// to be in sync with scheduled config-change job\n\t\t\t\t\t\t// (assume notifyc has cap of 1)\n\t\t\t\t\t\tselect {\n\t\t\t\t\t\tcase notifyc <- struct{}{}:\n\t\t\t\t\t\tcase <-r.stopped:\n\t\t\t\t\t\t\treturn\n\t\t\t\t\t\t}\n\t\t\t\t\t}\n\n\t\t\t\t\t// gofail: var raftBeforeFollowerSend struct{}\n\t\t\t\t\tr.transport.Send(msgs)\n\t\t\t\t} else {\n\t\t\t\t\t// leader already processed 'MsgSnap' and signaled\n\t\t\t\t\tnotifyc <- struct{}{}\n\t\t\t\t}\n\n\t\t\t\t// gofail: var raftBeforeAdvance struct{}\n\t\t\t\tr.Advance()\n\n\t\t\t\tif confChanged {\n\t\t\t\t\t// notify etcdserver that raft has already been notified or advanced.\n\t\t\t\t\traftAdvancedC <- struct{}{}\n\t\t\t\t}\n\t\t\tcase <-r.stopped:\n\t\t\t\treturn\n\t\t\t}\n\t\t}\n\t}()\n}\n\nfunc updateCommittedIndex(ap *toApply, rh *raftReadyHandler) {\n\tvar ci uint64\n\tif len(ap.entries) != 0 {\n\t\tci = ap.entries[len(ap.entries)-1].Index\n\t}\n\tif ap.snapshot.Metadata.Index > ci {\n\t\tci = ap.snapshot.Metadata.Index\n\t}\n\tif ci != 0 {\n\t\trh.updateCommittedIndex(ci)\n\t}\n}\n\nfunc (r *raftNode) processMessages(ms []raftpb.Message) []raftpb.Message {\n\tsentAppResp := false\n\tfor i := len(ms) - 1; i >= 0; i-- {\n\t\tif r.isIDRemoved(ms[i].To) {\n\t\t\tms[i].To = 0\n\t\t\tcontinue\n\t\t}\n\n\t\tif ms[i].Type == raftpb.MsgAppResp {\n\t\t\tif sentAppResp {\n\t\t\t\tms[i].To = 0\n\t\t\t} else {\n\t\t\t\tsentAppResp = true\n\t\t\t}\n\t\t}\n\n\t\tif ms[i].Type == raftpb.MsgSnap {\n\t\t\t// There are two separate data store: the store for v2, and the KV for v3.\n\t\t\t// The msgSnap only contains the most recent snapshot of store without KV.\n\t\t\t// So we need to redirect the msgSnap to etcd server main loop for merging in the\n\t\t\t// current store snapshot and KV snapshot.\n\t\t\tselect {\n\t\t\tcase r.msgSnapC <- ms[i]:\n\t\t\tdefault:\n\t\t\t\t// drop msgSnap if the inflight chan if full.\n\t\t\t}\n\t\t\tms[i].To = 0\n\t\t}\n\t\tif ms[i].Type == raftpb.MsgHeartbeat {\n\t\t\tok, exceed := r.td.Observe(ms[i].To)\n\t\t\tif !ok {\n\t\t\t\t// TODO: limit request rate.\n\t\t\t\tr.lg.Warn(\n\t\t\t\t\t\"leader failed to send out heartbeat on time; took too long, leader is overloaded likely from slow disk\",\n\t\t\t\t\tzap.String(\"to\", fmt.Sprintf(\"%x\", ms[i].To)),\n\t\t\t\t\tzap.Duration(\"heartbeat-interval\", r.heartbeat),\n\t\t\t\t\tzap.Duration(\"expected-duration\", 2*r.heartbeat),\n\t\t\t\t\tzap.Duration(\"exceeded-duration\", exceed),\n\t\t\t\t)\n\t\t\t\theartbeatSendFailures.Inc()\n\t\t\t}\n\t\t}\n\t}\n\treturn ms\n}\n\nfunc (r *raftNode) apply() chan toApply {\n\treturn r.applyc\n}\n\nfunc (r *raftNode) stop() {\n\tselect {\n\tcase r.stopped <- struct{}{}:\n\t\t// Not already stopped, so trigger it\n\tcase <-r.done:\n\t\t// Has already been stopped - no need to do anything\n\t\treturn\n\t}\n\t// Block until the stop has been acknowledged by start()\n\t<-r.done\n}\n\nfunc (r *raftNode) onStop() {\n\tr.Stop()\n\tr.ticker.Stop()\n\tr.transport.Stop()\n\tif err := r.storage.Close(); err != nil {\n\t\tr.lg.Panic(\"failed to close Raft storage\", zap.Error(err))\n\t}\n\tclose(r.done)\n}\n\n// for testing\nfunc (r *raftNode) pauseSending() {\n\tp := r.transport.(rafthttp.Pausable)\n\tp.Pause()\n}\n\nfunc (r *raftNode) resumeSending() {\n\tp := r.transport.(rafthttp.Pausable)\n\tp.Resume()\n}\n\n// advanceTicks advances ticks of Raft node.\n// This can be used for fast-forwarding election\n// ticks in multi data-center deployments, thus\n// speeding up election process.\nfunc (r *raftNode) advanceTicks(ticks int) {\n\t